form.script:
function updateFileName(input, update=false) {


    if(update){
    console.log("in changed file")
    const hiddenInputId = 'updated_certificate_' + input.id.split('_').pop();
    const hiddenInput = document.getElementById(hiddenInputId);
        console.log(hiddenInput.value)

    hiddenInput.value = `updated_${hiddenInput.value}`
        console.log(hiddenInput.value)

}



var inputId = input.getAttribute('id');
var label = document.querySelector(`label[for="${inputId}"]`);
var uploadText = label.querySelector('.upload-text');
var fileName = input.files.length > 0 ? input.files[0].name :
'Upload';
uploadText.textContent = fileName;

validateFileInput(input);






}

const urlParams = new URLSearchParams(window.location.search);
const group = urlParams.get('group');

if (group) {

    const hitem = document.getElementById('household-item1');
    hitem.style.display = 'list-item';


    const householdItem = document.getElementById('household-item2');
    householdItem.style.display = 'list-item';
    householdItem.querySelector('a').href = `/serviceprovider/group/update/${group}`;

    const fitem = document.getElementById('farmer_list_item');
    fitem.style.display = 'none';





}

const formTypeInput  = document.getElementById('form_type');
formTypeInput.value = group ? group : false;

$(document).ready(function () {
$('.selectpicker').selectpicker();
});
